// Ray-casting point-in-polygon — handles all gulfs, peninsulas, bays automatically
function pointInPolygon(lng, lat, polygon) {
  let inside = false;
  for (let i = 0, j = polygon.length - 1; i < polygon.length; j = i++) {
    const xi = polygon[i][0], yi = polygon[i][1];
    const xj = polygon[j][0], yj = polygon[j][1];
    if ((yi > lat) !== (yj > lat) && lng < (xj - xi) * (lat - yi) / (yj - yi) + xi) {
      inside = !inside;
    }
  }
  return inside;
}

function isLand(lat, lng) {
  if (lat < B.minLat || lat > B.maxLat || lng < B.minLng || lng > B.maxLng) return false;
  return GEO_POLYGONS.some(poly => pointInPolygon(lng, lat, poly));
}

function haversineKm(lat1, lng1, lat2, lng2) {
  const R = 6371, r = Math.PI / 180;
  const dLat = (lat2 - lat1) * r, dLng = (lng2 - lng1) * r;
  const a = Math.sin(dLat/2)**2 + Math.cos(lat1*r)*Math.cos(lat2*r)*Math.sin(dLng/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

function toSVG(lat, lng) {
  return {
    x: ((lng - B.minLng) / (B.maxLng - B.minLng)) * SVG_W,
    y: ((B.maxLat - lat) / (B.maxLat - B.minLat)) * SVG_H,
  };
}

// Build SVG paths and clipPath directly from the real geo coordinates
function polyToSVGPath(polygon) {
  const pts = polygon.map(([lng, lat]) => {
    const { x, y } = toSVG(lat, lng);
    return `${x.toFixed(1)},${y.toFixed(1)}`;
  });
  return `M ${pts[0]} ` + pts.slice(1).map(p => `L ${p}`).join(' ') + ' Z';
}
const COAST_PATHS = GEO_POLYGONS.map(polyToSVGPath);
const COAST_CLIP = COAST_PATHS.join(' ');

