export default function App() {
  // Multi-select: set of active tier ids
  const [activeTiers, setActiveTiers] = useState(new Set(["slow","fast","rapid","ultra"]));
  const [radiusKm, setRadiusKm] = useState(100);
  const [grid, setGrid] = useState(null);
  const [isCalc, setIsCalc] = useState(true);
  const [liveChargers, setLiveChargers] = useState(null);
  const [fetchStatus, setFetchStatus] = useState("loading");
  const [hovered, setHovered] = useState(null);

  // Derive "all selected" state
  const allSelected = activeTiers.size === TIERS.length;

  function toggleTier(id) {
    setActiveTiers(prev => {
      const next = new Set(prev);
      if (next.has(id)) { next.delete(id); } else { next.add(id); }
      return next.size === 0 ? prev : next; // prevent empty selection
    });
  }

  function toggleAll() {
    if (allSelected) {
      // deselect all → select only ultra
      setActiveTiers(new Set(["ultra"]));
    } else {
      setActiveTiers(new Set(TIERS.map(t => t.id)));
    }
  }

  const source = liveChargers || CHARGERS;
  const filtered = source.filter(c =>
    TIERS.some(t => activeTiers.has(t.id) && c.kw >= t.minKw && c.kw < t.maxKw)
  );

  // Active tier colors for legend / stats
  const activeColors = TIERS.filter(t => activeTiers.has(t.id)).map(t => t.color);
  const displayColor = activeColors.length === 1 ? activeColors[0] : "#22c55e";

  useEffect(() => {
    // Fetch from OCM in parallel batches covering all of Australia
    // OCM maxresults=10000 is the API limit per call, so we tile by lat bands
    const parseOCM = (data) => data.map(s => {
      let kw = 22;
      if (s.Connections?.length > 0) {
        const mx = Math.max(...s.Connections.map(c => c.PowerKW || 0));
        if (mx > 0) kw = mx;
      }
      return { lat: s.AddressInfo?.Latitude, lng: s.AddressInfo?.Longitude, kw };
    }).filter(s => s.lat && s.lng);

    const base = "https://api.openchargemap.io/v3/poi/?output=json&countrycode=AU&compact=true&verbose=false&maxresults=10000";
    
    // Fetch two lat bands to get better coverage (OCM limits per call)
    Promise.all([
      fetch(base).then(r => r.ok ? r.json() : []).catch(() => []),
      fetch(base + "&latitude=-25&longitude=133&distance=2000&distanceunit=km").then(r => r.ok ? r.json() : []).catch(() => []),
    ]).then(([a, b]) => {
      const all = [...a, ...b];
      if (all.length === 0) { setFetchStatus("fallback"); return; }
      // Deduplicate by OCM ID
      const seen = new Set();
      const deduped = all.filter(s => {
        if (seen.has(s.ID)) return false;
        seen.add(s.ID);
        return true;
      });
      const parsed = parseOCM(deduped);
      setLiveChargers(parsed);
      setFetchStatus("live");
    }).catch(() => setFetchStatus("fallback"));
  }, []);

  useEffect(() => {
    setIsCalc(true);
    const t = setTimeout(() => {
      const cw = SVG_W / GRID_COLS, ch = SVG_H / GRID_ROWS;
      const cells = [];
      for (let row = 0; row < GRID_ROWS; row++) {
        for (let col = 0; col < GRID_COLS; col++) {
          const lat = B.maxLat - ((row + 0.5) / GRID_ROWS) * (B.maxLat - B.minLat);
          const lng = B.minLng + ((col + 0.5) / GRID_COLS) * (B.maxLng - B.minLng);
          if (!isLand(lat, lng)) { cells.push({ row, col, covered: null }); continue; }
          let minDist = Infinity;
          for (const c of filtered) {
            const d = haversineKm(lat, lng, c.lat, c.lng);
            if (d < minDist) minDist = d;
            if (minDist < 5) break;
          }
          cells.push({ row, col, covered: minDist <= radiusKm, dist: Math.round(minDist) });
        }
      }
      setGrid(cells);
      setIsCalc(false);
    }, 20);
    return () => clearTimeout(t);
  }, [activeTiers, radiusKm, liveChargers]);

  const cw = SVG_W / GRID_COLS, ch = SVG_H / GRID_ROWS;
  const covCount = grid ? grid.filter(c => c.covered === true).length : 0;
  const landCount = grid ? grid.filter(c => c.covered !== null).length : 0;
  const pct = landCount > 0 ? Math.round(covCount / landCount * 100) : 0;

  return (
    <div style={{ background: "#07101f", minHeight: "100vh", fontFamily: "'Space Mono',monospace", color: "#e2e8f0", padding: "16px 12px", display: "flex", flexDirection: "column", alignItems: "center" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Space+Mono:wght@400;700&family=Syne:wght@700;800&display=swap');
        * { box-sizing: border-box; }
        .tb { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.1); color: #64748b; padding: 6px 13px; border-radius: 5px; cursor: pointer; font-family: 'Space Mono',monospace; font-size: 11px; transition: all 0.15s; white-space: nowrap; }
        .tb:hover { background: rgba(255,255,255,0.08); color: #e2e8f0; }
        .tb.on { color: #07101f !important; font-weight: 700; border-color: transparent; }
        .tb.all-on { background: #22c55e; color: #07101f; font-weight: 700; border-color: transparent; }
        .tb.all-off { background: rgba(255,255,255,0.04); color: #64748b; }
        .st { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); border-radius: 8px; padding: 10px 16px; text-align: center; min-width: 76px; }
        input[type=range] { accent-color: #38bdf8; cursor: pointer; }
      `}</style>

      <div style={{ textAlign: "center", marginBottom: 14 }}>
        <div style={{ fontFamily: "'Syne',sans-serif", fontSize: 22, fontWeight: 800, letterSpacing: "-0.5px" }}>🔋 Australia EV Coverage</div>
        <div style={{ fontSize: 10, color: "#334155", marginTop: 3 }}>
          {fetchStatus === "live" ? `✅ LIVE · ${source.length.toLocaleString()} stations · Open Charge Map`
            : fetchStatus === "loading" ? "⏳ Fetching live charger data…"
            : `📍 ${source.length.toLocaleString()} stations · OSM + Chargefox · Tesla · Evie · Ampol`}
        </div>
      </div>

      {/* Tier multi-select */}
      <div style={{ display: "flex", gap: 6, flexWrap: "wrap", justifyContent: "center", marginBottom: 10 }}>
        <button className={`tb ${allSelected ? "all-on" : "all-off"}`} onClick={toggleAll}>
          All speeds
        </button>
        {TIERS.map(t => (
          <button key={t.id} className={`tb ${activeTiers.has(t.id) ? "on" : ""}`}
            style={activeTiers.has(t.id) ? { background: t.color } : {}}
            onClick={() => toggleTier(t.id)}>
            {t.label}
          </button>
        ))}
      </div>

      {/* Radius */}
      <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 12 }}>
        <span style={{ fontSize: 10, color: "#475569" }}>RADIUS</span>
        <input type="range" min={25} max={300} step={25} value={radiusKm}
          onChange={e => setRadiusKm(+e.target.value)} style={{ width: 130 }} />
        <span style={{ fontSize: 13, fontWeight: 700 }}>{radiusKm} km</span>
      </div>

      {/* Stats */}
      <div style={{ display: "flex", gap: 8, marginBottom: 12, flexWrap: "wrap", justifyContent: "center" }}>
        <div className="st"><div style={{ fontSize: 20, fontWeight: 700, color: displayColor }}>{pct}%</div><div style={{ fontSize: 9, color: "#475569", marginTop: 1 }}>COVERED</div></div>
        <div className="st"><div style={{ fontSize: 20, fontWeight: 700 }}>{filtered.length.toLocaleString()}</div><div style={{ fontSize: 9, color: "#475569", marginTop: 1 }}>STATIONS</div></div>
        <div className="st"><div style={{ fontSize: 20, fontWeight: 700, color: "#ef4444" }}>{100 - pct}%</div><div style={{ fontSize: 9, color: "#475569", marginTop: 1 }}>UNCOVERED</div></div>
      </div>

      {/* Map */}
      <div style={{ position: "relative", borderRadius: 8, overflow: "hidden", border: "1px solid rgba(255,255,255,0.07)", background: "#1565a0", width: "100%", maxWidth: SVG_W }}>
        {isCalc && (
          <div style={{ position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center", background: "rgba(21,101,160,0.85)", zIndex: 5 }}>
            <span style={{ fontSize: 11, color: "#bfdbfe", letterSpacing: "0.08em" }}>CALCULATING…</span>
          </div>
        )}
        <svg width="100%" viewBox={`0 0 ${SVG_W} ${SVG_H}`} style={{ display: "block" }}>
          <defs>
            {/* Clip path: coverage grid only shows inside Australia's coastline */}
            <clipPath id="aus-clip">
              <path d={COAST_CLIP} />
            </clipPath>
          </defs>
          {/* Ocean background — fills entire SVG */}
          <rect width={SVG_W} height={SVG_H} fill="#1565a0" />
          {/* Slightly lighter ocean texture in the bounding box */}
          <rect width={SVG_W} height={SVG_H} fill="#0e4f8a" opacity={0.4} />
          {/* Coverage grid — clipped to land shape */}
          <g clipPath="url(#aus-clip)">
            {/* Land base colour under coverage */}
            <rect width={SVG_W} height={SVG_H} fill="#2d2d2d" opacity={0.4} />
            {grid && grid.map(cell => {
              if (cell.covered === null) return null;
              const x = cell.col * cw, y = cell.row * ch;
              return (
                <rect key={`${cell.row}-${cell.col}`} x={x} y={y} width={cw + 0.5} height={ch + 0.5}
                  fill={cell.covered ? displayColor : "#ef4444"}
                  opacity={cell.covered ? 0.65 : 0.45}
                  onMouseEnter={() => setHovered({ ...cell, px: x + cw / 2, py: y })}
                  onMouseLeave={() => setHovered(null)} />
              );
            })}
          </g>
          {/* Coastline outline — on top of everything */}
          {COAST_PATHS.map((d, i) => <path key={i} d={d} fill="none" stroke="rgba(0,0,0,0.9)" strokeWidth={1.8} strokeLinejoin="round" strokeLinecap="round" />)}
          {/* Station dots — show per-tier color */}
          {filtered.length <= 3000 && filtered.map((c, i) => {
            const { x, y } = toSVG(c.lat, c.lng);
            const tier = TIERS.find(t => c.kw >= t.minKw && c.kw < t.maxKw) || TIERS[TIERS.length - 1];
            const r = c.kw >= 200 ? 3 : c.kw >= 50 ? 2 : 1.5;
            return <circle key={i} cx={x} cy={y} r={r} fill={activeTiers.size === 1 ? "white" : tier.color}
              opacity={0.85} stroke="rgba(0,0,0,0.3)" strokeWidth={0.4} />;
          })}
          {/* State labels */}
          {[
            { n: "WA", lat: -26.5, lng: 121.5 },
            { n: "NT", lat: -20, lng: 133.5 },
            { n: "QLD", lat: -22, lng: 144.5 },
            { n: "SA", lat: -30, lng: 135.5 },
            { n: "NSW", lat: -32.5, lng: 146.0 },
            { n: "VIC", lat: -36.8, lng: 144.5 },
            { n: "TAS", lat: -42.2, lng: 146.6 },
            { n: "ACT", lat: -35.5, lng: 149.1 },
          ].map(({ n, lat, lng }) => {
            const { x, y } = toSVG(lat, lng);
            return <text key={n} x={x} y={y} textAnchor="middle"
              fill="rgba(255,255,255,0.15)" fontSize={n === "WA" ? 20 : 11}
              fontFamily="'Syne',sans-serif" fontWeight={700} letterSpacing="0.08em">{n}</text>;
          })}
        </svg>
        {hovered && hovered.covered !== null && (
          <div style={{
            position: "absolute",
            left: Math.min(hovered.px + 8, SVG_W - 150),
            top: Math.max(hovered.py - 30, 4),
            background: "rgba(4,12,24,0.97)", border: "1px solid rgba(255,255,255,0.12)",
            borderRadius: 4, padding: "4px 9px", fontSize: 11, pointerEvents: "none", zIndex: 10, whiteSpace: "nowrap"
          }}>
            {hovered.covered ? `✅ ${hovered.dist}km to nearest` : `❌ ${hovered.dist}km to nearest`}
          </div>
        )}
      </div>

      {/* Legend */}
      <div style={{ display: "flex", gap: 16, marginTop: 10, fontSize: 10, color: "#475569", flexWrap: "wrap", justifyContent: "center", alignItems: "center" }}>
        <span><span style={{ display: "inline-block", width: 11, height: 11, borderRadius: 2, background: displayColor, opacity: 0.7, verticalAlign: "middle", marginRight: 4 }} />Within {radiusKm}km</span>
        <span><span style={{ display: "inline-block", width: 11, height: 11, borderRadius: 2, background: "#ef4444", opacity: 0.4, verticalAlign: "middle", marginRight: 4 }} />Beyond {radiusKm}km</span>
        {TIERS.filter(t => activeTiers.has(t.id)).map(t => (
          <span key={t.id}><span style={{ display: "inline-block", width: 7, height: 7, borderRadius: "50%", background: t.color, verticalAlign: "middle", marginRight: 4 }} />{t.label}</span>
        ))}
      </div>
      <div style={{ marginTop: 6, fontSize: 9, color: "#1e293b", textAlign: "center" }}>
        Open Charge Map · Chargefox · Tesla Superchargers · Evie · Ampol · NRMA · BP Pulse · Regional
      </div>
    </div>
  );
}
